SELECT COUNT(DISTINCT P.PK) AS QUANTIDADE FROM LATTES_PRODTEC P JOIN LATTES_P_PRODTEC LP ON LP.FK_PRODTEC = P.PK JOIN SERVIDOR S ON S.PK_SIAPE = LP.FK_SIAPE WHERE LOWER(P.NATUREZA) LIKE LOWER('%consultoria%') AND P.ANO = 2022 AND LOWER(COALESCE(S.SIGLA_CAMPUS,'')) = 'oes' AND LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%enfermagem%'